// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.packed;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotEquals;

import org.junit.jupiter.api.Test;

class PackedWinnerTableTest {

	@Test
	void denseDefaultSlotRetainsOnlyTheDeterministicCheapestWinner() {
		PackedWinnerTable winners = new PackedWinnerTable(4, 4, 8, 1);
		int[] children = { 7, 8 };

		int winner = winners.offer(3, 1, 0, 0, 0, 40, 2.0d, 20.0d, 20.0d, children, 0, 2);
		assertEquals(winner, winners.offer(3, 1, 0, 0, 0, 41, 1.0d, 30.0d, 30.0d, children, 0, 2));
		assertEquals(40, winners.physicalExpressionId(winner));

		assertEquals(winner, winners.offer(3, 1, 0, 0, 0, 42, 1.0d, 10.0d, 10.0d, new int[] { 9 }, 0, 1));
		assertEquals(42, winners.physicalExpressionId(winner));
		assertEquals(10.0d, winners.totalCost(winner));
		assertEquals(1, winners.childCount(winner));
		assertEquals(9, winners.childWinnerId(winner, 0));

		assertEquals(winner, winners.offer(3, 1, 0, 0, 0, 39, 1.0d, 10.0d, 10.0d, children, 0, 2));
		assertEquals(39, winners.physicalExpressionId(winner));
		assertEquals(1, winners.size());
	}

	@Test
	void requiredPropertyAndEveryGoalContextSplitWinnerIdentity() {
		PackedWinnerTable winners = new PackedWinnerTable(2, 16, 0, 1);
		int[] none = new int[0];

		int baseline = winners.offer(1, 2, 3, 4, 5, 10, 0.0d, 1.0d, 1.0d, none, 0, 0);
		assertNotEquals(baseline, winners.offer(2, 2, 3, 4, 5, 10, 0.0d, 1.0d, 1.0d, none, 0, 0));
		assertNotEquals(baseline, winners.offer(1, 6, 3, 4, 5, 10, 0.0d, 1.0d, 1.0d, none, 0, 0));
		assertNotEquals(baseline, winners.offer(1, 2, 7, 4, 5, 10, 0.0d, 1.0d, 1.0d, none, 0, 0));
		assertNotEquals(baseline, winners.offer(1, 2, 3, 8, 5, 10, 0.0d, 1.0d, 1.0d, none, 0, 0));
		assertNotEquals(baseline, winners.offer(1, 2, 3, 4, 9, 10, 0.0d, 1.0d, 1.0d, none, 0, 0));
		assertEquals(baseline, winners.find(1, 2, 3, 4, 5));
	}

	@Test
	void forcedHashCollisionDoesNotCoalesceUnequalGoals() {
		PackedWinnerTable winners = new PackedWinnerTable(2, 2, 0, 1);
		int[] none = new int[0];

		int left = winners.offerHashed(23L, 1, 2, 3, 4, 5, 10, 0.0d, 1.0d, 1.0d, none, 0, 0);
		int right = winners.offerHashed(23L, 1, 2, 3, 4, 6, 10, 0.0d, 1.0d, 1.0d, none, 0, 0);

		assertNotEquals(left, right);
		assertEquals(2, winners.size());
	}
}
